const HeaderAndFooter = () => {
  const headerHeight = 400;
  return (
    <div
      style={{
        width: "100%",
        height: "100vh",
        overflowY: "auto",
        // opt out browser's scroll anchoring on header/footer because it will conflict to scroll anchoring of virtualizer
        overflowAnchor: "none",
      }}
    >
      <div style={{ backgroundColor: "burlywood", height: headerHeight }}>
        header
      </div>
      <Virtualizer startMargin={headerHeight}>{createRows(1000)}</Virtualizer>
      <div style={{ backgroundColor: "steelblue", height: 600 }}>footer</div>
    </div>
  );
};

const StickyHeaderAndFooter = () => {
  const headerHeight = 40;
  return (
    <div
      style={{
        width: "100%",
        height: "100vh",
        overflowY: "auto",
        // opt out browser's scroll anchoring on header/footer because it will conflict to scroll anchoring of virtualizer
        overflowAnchor: "none",
      }}
    >
      <div
        style={{
          position: "sticky",
          backgroundColor: "burlywood",
          height: headerHeight,
          top: 0,
          zIndex: 1,
        }}
      >
        header
      </div>
      <Virtualizer startMargin={headerHeight}>{createRows(1000)}</Virtualizer>
      <div
        style={{
          position: "sticky",
          backgroundColor: "steelblue",
          height: 60,
          bottom: 0,
        }}
      >
        footer
      </div>
    </div>
  );
};

const Overflow = () => {
  const spacerSize = 24;
  return (
    <div
      style={{
        boxSizing: "border-box",
        height: "100vh",
        overflowY: "auto",
        // opt out browser's scroll anchoring on header/footer because it will conflict to scroll anchoring of virtualizer
