            checked={prepend}
            onChange={() => {
              setPrepend((prev) => !prev);
            }}
          />
          prepend
        </label>
        <label style={{ marginRight: 4 }}>
          <input
            type="radio"
            style={{ marginLeft: 4 }}
            checked={increase}
            onChange={() => {
              setIncrease(true);
            }}
          />
          increase
        </label>
        <label style={{ marginRight: 4 }}>
          <input
            type="radio"
            style={{ marginLeft: 4 }}
            checked={!increase}
            onChange={() => {
              setIncrease(false);
            }}
          />
          decrease
        </label>
        <input
          style={{ marginLeft: 4 }}
          value={amount}
          type="number"
          min={1}
          max={10000}
          step={1}
          onChange={(e) => {
            setAmount(Number(e.target.value));
          }}
        />
      </div>
      <div>
        <label style={{ marginRight: 16 }}>
          <input
            type="checkbox"
            style={{ marginLeft: 4 }}
            checked={auto}
            onChange={() => {
              setAuto((prev) => !prev);
            }}
          />
          auto
        </label>
        <button
          onClick={() => {
            update();
          }}
        >
          update
        </button>
      </div>
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          // opt out browser's scroll anchoring on header/footer because it will conflict to scroll anchoring of virtualizer
          overflowAnchor: "none",
          // flex style for spacer
          display: "flex",
          flexDirection: "column",
        }}
      >
        <div
          style={{
            // spacer to align virtualizer to the bottom when all items are visible in the viewport
            flexGrow: 1,
          }}
        />
        <Virtualizer shift={prepend}>
          {rows.map((d) => (
            <div
              key={d.id}
              style={{
                height: heights[Math.abs(d.index) % 4],
                borderBottom: "solid 1px #ccc",
                background: "#fff",
              }}
            >
              {d.index}
            </div>
          ))}
        </Virtualizer>
      </div>
    </div>
  );
};

const BiDirectionalInfiniteScrolling = () => {
  const id = useRef(0);
  const createRows = (num: number) => {
    const heights = [20, 40, 80, 77];
    return Array.from({ length: num }).map(() => {
      const i = id.current++;
      return (
        <div
          key={i}
          style={{
            height: heights[i % 4],
            borderBottom: "solid 1px #ccc",
            background: "#fff",
          }}
        >
          {i}
        </div>
      );
    });
  };

  const [shifting, setShifting] = useState(false);
  const [startFetching, setStartFetching] = useState(false);
  const [endFetching, setEndFetching] = useState(false);
  const fetchStart = async () => {
    setShifting(true);

    setStartFetching(true);
    await delay(1000);
    setItems((prev) => [...createRows(ITEM_BATCH_COUNT).reverse(), ...prev]);
    setStartFetching(false);
  };
  const fetchEnd = async () => {
    setShifting(false);

    setEndFetching(true);
    await delay(1000);
    setItems((prev) => [...prev, ...createRows(ITEM_BATCH_COUNT)]);
    setEndFetching(false);
  };

  const ref = useRef<VirtualizerHandle>(null);
  const ITEM_BATCH_COUNT = 100;
  const [items, setItems] = useState(() => createRows(ITEM_BATCH_COUNT * 2));
  const THRESHOLD = 50;
  const count = items.length;
  const startFetchedCountRef = useRef(-1);
  const endFetchedCountRef = useRef(-1);

  const ready = useRef(false);
  useEffect(() => {
    ref.current?.scrollToIndex(items.length / 2 + 1);
    ready.current = true;
  }, []);

  const spinnerHeight = 100;

  return (
    <div
      style={{
        height: "100vh",
        overflowY: "auto",
        // opt out browser's scroll anchoring on header/footer because it will conflict to scroll anchoring of virtualizer
        overflowAnchor: "none",
      }}
    >
      <Spinner
        height={spinnerHeight}
        style={startFetching ? undefined : { visibility: "hidden" }}
      />
      <Virtualizer
        ref={ref}
        shift={shifting ? true : false}
        startMargin={spinnerHeight}
        onScroll={async () => {
          if (!ready.current) return;
          if (!ref.current) return;

          const startOffset = ref.current.scrollOffset;
          const endOffset = startOffset + ref.current.viewportSize;
          if (
            endFetchedCountRef.current < count &&
            ref.current.findItemIndex(endOffset) + THRESHOLD > count
          ) {
            endFetchedCountRef.current = count;
            await fetchEnd();
          } else if (
            startFetchedCountRef.current < count &&
            ref.current.findItemIndex(startOffset) - THRESHOLD < 0
          ) {
            startFetchedCountRef.current = count;
            await fetchStart();
          }
        }}
      >
        {items}
      </Virtualizer>
      <Spinner
        height={spinnerHeight}
        style={endFetching ? undefined : { visibility: "hidden" }}
      />
    </div>
  );
};

