const Default = () => {
  const id = useRef(0);
  const [messages, setMessages] = useState<Message[]>([]);

  useEffect(() => {
    let message: Message | null = null;
    let cursor = 0;
    let timerId = setInterval(() => {
      if (!message || cursor >= message.text.length) {
        cursor = 0;
        const m = (message = createMarkdownMessage(++id.current));
        setMessages((prev) => [...prev, { ...m, text: "" }]);
      }

      cursor = Math.min(cursor + 100, message.text.length);
      const nextText = message.text.slice(0, cursor);
      setMessages((prev) => {
        const last = prev.at(-1)!;
        return [...prev.slice(0, -1), { ...last, text: nextText }];
      });
    }, 100);
    return () => {
      clearInterval(timerId);
    };
  }, []);

  return (
    <div
      style={{
        height: "100%",
        overflowY: "auto",
        overflowAnchor: "none",
        maxWidth: 400,
      }}
    >
      <div style={{ height: 100 }}></div>
      <Virtualizer startMargin={100} data={messages}>
        {(message) => (
          <div
            key={message.id}
            style={{
              background: "white",
              padding: "1rem",
              margin: "1rem",
              borderRadius: "1rem",
            }}
          >
            <ReactMarkdown
              remarkPlugins={[remarkGfm]}
              components={markdownComponents}
            >
              {message.text}
            </ReactMarkdown>
          </div>
        )}
      </Virtualizer>
      <div style={{ height: 100 }}></div>
    </div>
  );
};

