    return TAGS.filter((t) =>
      t.label.toLowerCase().includes(normalizedValue),
    );
  }, [value]);

  return (
    <>
      <Command label="Command Menu" value={selected} shouldFilter={false}>
        <Command.Input value={value} onValueChange={setValue} />
